+        const buffer_module = qjs.JS_GetPropertyStr(ctx, modules, "buffer");
+        if (!qjs.JS_IsUndefined(buffer_module)) {
+            return buffer_module;
+        }
+    }
+
+    return qjs.JS_NewObject(ctx);
+}
